```solidity
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract SettlementContract {
    enum State { PaymentPending, PaymentSettled, Withdrawals }

    struct Payment {
        uint256 sellerAmount;
        uint256 creatorRoyalty;
        uint256 deadline;
        bytes signature;
    }

    address public operator;
    address public adamWallet;
    mapping(uint256 => Payment) private payments;
    mapping(address => bool) private exclusives;

    event Settled(uint256 indexed id);
    event ERC20Withdrawed(address token, address recipient, uint256 amount);
    event OperatorChanged(address newOperator);
    event AdamWalletChanged(address newAdamWallet);

    modifier onlyOperator() {
        require(msg.sender == operator, "Not authorized");
        _;
    }

    constructor() {
        operator = msg.sender;
        adamWallet = msg.sender;
    }

    function settle(
        uint256 id,
        uint256 sellerAmount,
        uint256 creatorRoyalty,
        uint256 deadline,
        bytes memory signature
    ) external {
        require(state(id) == State.PaymentPending, "Payment already settled");
        require(block.timestamp <= deadline, "Deadline exceeded");

        if (exclusives[msg.sender]) {
            require(verifySignature(id, sellerAmount, creatorRoyalty, deadline, signature), "Invalid signature");
        }

        uint256 totalAmount = sellerAmount + creatorRoyalty;
        require(IERC20(msg.sender).transferFrom(msg.sender, address(this), totalAmount), "Transfer failed");

        IERC20(msg.sender).transfer(payments[id].sellerAmount > 0 ? payments[id].sellerAmount : sellerAmount, address(payments[id].sellerAmount > 0 ? payments[id].seller : seller));
        IERC20(msg.sender).transfer(payments[id].creatorRoyalty > 0 ? payments[id].creatorRoyalty : creatorRoyalty, address(payments[id].creatorRoyalty > 0 ? payments[id].creator : msg.sender));
        IERC20(msg.sender).transfer(adamWallet, totalAmount - (payments[id].sellerAmount + payments[id].creatorRoyalty));

        payments[id] = Payment({
            sellerAmount: sellerAmount,
            creatorRoyalty: creatorRoyalty,
            deadline: deadline,
            signature: signature
        });

        emit Settled(id);
    }

    function withdrawERC20(address token, uint256 amount) external {
        require(state(id) == State.PaymentSettled, "Payment not settled yet");
        require(IERC20(token).balanceOf(address(this)) >= amount, "Insufficient balance");

        IERC20(token).transfer(msg.sender, amount);

        emit ERC20Withdrawed(token, msg.sender, amount);
    }

    function changeOperator(address newOperator) external onlyOperator {
        operator = newOperator;

        emit OperatorChanged(newOperator);
    }

    function changeAdamWallet(address newAdamWallet) external onlyOperator {
        adamWallet = newAdamWallet;

        emit AdamWalletChanged(newAdamWallet);
    }

    function verifySignature(
        uint256 id,
        uint256 sellerAmount,
        uint256 creatorRoyalty,
        uint256 deadline,
        bytes memory signature
    ) internal view returns (bool) {
        bytes32 messageHash = keccak256(abi.encodePacked(id, sellerAmount, creatorRoyalty, deadline));
        return recoverSigner(messageHash, signature) == operator;
    }

    function recoverSigner(bytes32 messageHash, bytes memory signature) internal pure returns (address) {
        bytes32 r;
        bytes32 s;
        uint8 v;

        // solhint-disable-next-line no-inline-assembly
        assembly {
            r := mload(add(signature, 0x20))
            s := mload(add(signature, 0x40))
            v := byte(0, mload(add(signature, 0x60)))
        }

        if (v < 27) {
            v += 27;
        }

        return ecrecover(messageHash, v, r, s);
    }

    function state(uint256 id) public view returns (State) {
        if (payments[id].deadline == 0) {
            return State.PaymentPending;
        } else if (block.timestamp > payments[id].deadline) {
            return State.PaymentSettled;
        } else {
            return State.Withdrawals;
        }
    }
}
