import "@openzeppelin/contracts/token/ERC20/utils/ERC20VotesComp.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

contract SettlementContract {
    enum State { PaymentPending, PaymentSettled, Withdrawals }

    struct Payment {
        uint256 sellerAmount;
        uint256 creatorRoyalty;
        uint256 deadline;
        bytes signature;
        bool settled;
    }

    address public operator;
    address public adamWallet;
    mapping(uint256 => Payment) private payments;
    mapping(address => bool) private exclusives;

    event Settled(uint256 indexed id);
    event ERC20Withdrawed(address token, address recipient, uint256 amount);
    event OperatorChanged(address newOperator);
    event AdamWalletChanged(address newAdamWallet);

    modifier onlyOperator() {
        require(msg.sender == operator, "Not authorized");
        _;
    }

    constructor() {
        operator = msg.sender;
        adamWallet = msg.sender;
    }

    function settle(
        uint256 id,
        uint256 sellerAmount,
        uint256 creatorRoyalty,
        uint256 deadline,
        bytes memory signature
    ) external {
        Payment storage payment = payments[id];

        // Checks
        require(state(id) == State.PaymentPending, "Payment already settled");
        require(block.timestamp <= deadline, "Deadline exceeded");
        require(exclusives[msg.sender] || verifySignature(id, sellerAmount, creatorRoyalty, deadline, signature), "Invalid signature");

        // Effects
        uint256 totalAmount = sellerAmount + creatorRoyalty;
        payment.sellerAmount = sellerAmount;
        payment.creatorRoyalty = creatorRoyalty;
        payment.deadline = deadline;
        payment.signature = signature;
        payment.settled = true;

        // Interactions
        require(IERC20(msg.sender).transferFrom(msg.sender, address(this), totalAmount), "Transfer failed");
        IERC20(msg.sender).transfer(payment.sellerAmount > 0 ? payment.sellerAmount : sellerAmount, address(payment.sellerAmount > 0 ? payment.seller : msg.sender));
        IERC20(msg.sender).transfer(payment.creatorRoyalty > 0 ? payment.creatorRoyalty : creatorRoyalty, address(payment.creatorRoyalty > 0 ? payment.creator : msg.sender));
        IERC20(msg.sender).transfer(adamWallet, totalAmount - (payment.sellerAmount + payment.creatorRoyalty));

        emit Settled(id);
    }

    function withdrawERC20(address token, uint256 amount) external onlyOperator {
        require(state(id) == State.PaymentSettled, "Payment not settled yet");
        require(IERC20(token).balanceOf(address(this)) >= amount, "Insufficient balance");

        IERC20(token).transfer(msg.sender, amount);

        emit ERC20Withdrawed(token, msg.sender, amount);
    }

    function changeOperator(address newOperator) external onlyOperator {
        operator = newOperator;

        emit OperatorChanged(newOperator);
    }

    function changeAdamWallet(address newAdamWallet) external onlyOperator {
        adamWallet = newAdamWallet;

        emit AdamWalletChanged(newAdamWallet);
    }

    function verifySignature(
        uint256 id,
        uint256 sellerAmount,
        uint256 creatorRoyalty,
        uint256 deadline,
        bytes memory signature
    ) internal view returns (bool) {
        bytes32 messageHash = ECDSA.toEthSignedMessageHash(keccak256(abi.encodePacked(id, sellerAmount, creatorRoyalty, deadline)));
        return ECDSA.recover(messageHash, signature) == operator;
    }

    function state(uint256 id) public view returns (State) {
        Payment storage payment = payments[id];
        if (!payment.settled) {
            return State.PaymentPending;
        } else if (payment.sellerAmount > 0 && payment.creatorRoyalty > 0) {
            return State.PaymentSettled;
        } else {
            return State.Withdrawals;
        }
    }
}
